sp_page.css:
/* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
Container 1 Row has CSS selector row auto added to our ask of fill-section flex-row
and we have to override the row style else we get a scrollbar at the bottom of the page
see div.sp-row-content.fill-section.flex-row.row below
!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!! */
div.sp-row-content.fill-section.flex-row.row,
div.sp-row-content.fill-section.flexbox.row {
  margin-left: 0;
  margin-right: 0;
}

/* Tasker Data Table */
.v1fe908a64fc71300d236eb118110c78a {
  display: flex;
  flex-grow: 1;
  justify-content: center;
}

//---------------------------------------------------------------------------------
//KT Wrapping Table Headers
.v5001b062d7101200b0b044580e6103eb .th-title {
  display: inline-block;
  color: $primary;
  //KT
  white-space: normal;
}
.text-nowrap {
  white-space: normal;
}
